1	/**
2	 * EDT-01 — universal grip protocol.
3	 *
4	 * Pure data-shape module. Element kinds opt in to in-place editing by
5	 * supplying an `ElementGripProvider`; the plan canvas raycasts the
6	 * grips before element pick so they take hover priority. This file
7	 * ships the wall provider as the load-bearing slice — door, window,
8	 * floor, column, beam, section grips are deferred (each is roughly
9	 * 0.5d of follow-up using this protocol).
10	 */
11	import type { Element, XY } from '@bim-ai/core';
12	
13	/** A draft mutation produced by a grip during drag — used by the
14	 *  plan canvas to render a live preview before the command commits.
15	 *  Today only `wall` is wired; `unknown` lets future kinds slot in
16	 *  without a protocol change. */
17	export type DraftMutation =
18	  | {
19	      kind: 'wall';
20	      id: string;
21	      start: XY;
22	      end: XY;
23	      thicknessMm: number;
24	    }
25	  | { kind: 'unknown'; id: string };
26	
27	/** Engine command shape — matches the JSON the
28	 *  `onSemanticCommand(cmd: Record<string, unknown>)` callback expects. */
29	export type GripCommand = Record<string, unknown>;
30	
31	export interface GripDescriptor {
32	  id: string;
33	  positionMm: XY;
34	  shape: 'square' | 'circle' | 'arrow';
35	  axis: 'x' | 'y' | 'free' | 'normal_to_element';
36	  hint?: string;
37	  /** Live-preview mutation while dragging. Returns a draft element so
38	   *  the canvas can paint the in-flight geometry without committing. */
39	  onDrag: (deltaMm: XY) => DraftMutation;
40	  /** Commit-on-release. Returns the engine command. */
41	  onCommit: (deltaMm: XY) => GripCommand;
42	  /** Numeric override during drag. The interpretation of `absoluteMm`
43	   *  is grip-specific (e.g. wall length for an endpoint grip; new
44	   *  thickness for a thickness grip). */
45	  onNumericOverride: (absoluteMm: number) => GripCommand;
46	}
47	
48	/** Per-element-kind context the provider may need (placeholder shape
49	 *  so each kind can extend without a protocol bump). */
50	export interface PlanContext {
51	  /** Currently-active level — drives whether off-level neighbours are
52	   *  considered for the grip-set. */
53	  activeLevelId?: string;
54	}
55	
56	export interface ElementGripProvider<E extends Element> {
57	  grips(element: E, context: PlanContext): GripDescriptor[];
58	}
59	
60	/* ─── Wall provider ────────────────────────────────────────────────── */
61	
62	export type Wall = Extract<Element, { kind: 'wall' }>;
63	
64	function midpoint(a: XY, b: XY): XY {
65	  return { xMm: (a.xMm + b.xMm) / 2, yMm: (a.yMm + b.yMm) / 2 };
66	}
67	
68	function lengthMm(a: XY, b: XY): number {
69	  const dx = b.xMm - a.xMm;
70	  const dy = b.yMm - a.yMm;
71	  return Math.hypot(dx, dy);
72	}
73	
74	function unitNormal(a: XY, b: XY): XY {
75	  const dx = b.xMm - a.xMm;
76	  const dy = b.yMm - a.yMm;
77	  const len = Math.hypot(dx, dy);
78	  if (len === 0) return { xMm: 0, yMm: 1 };
79	  // Rotate (dx, dy) by 90° CCW.
80	  return { xMm: -dy / len, yMm: dx / len };
81	}
82	
83	/** Project (deltaX, deltaY) onto the unit normal `n`, returning the
84	 *  signed scalar magnitude. */
85	function projectOntoNormal(delta: XY, n: XY): number {
86	  return delta.xMm * n.xMm + delta.yMm * n.yMm;
87	}
88	
89	export const wallGripProvider: ElementGripProvider<Wall> = {
90	  grips(wall: Wall): GripDescriptor[] {
91	    const start = wall.start;
92	    const end = wall.end;
93	    const mid = midpoint(start, end);
94	    const n = unitNormal(start, end);
95	    const halfT = wall.thicknessMm / 2;
96	    const thicknessHandlePos: XY = {
97	      xMm: mid.xMm + n.xMm * halfT,
98	      yMm: mid.yMm + n.yMm * halfT,
99	    };
100	
101	    const startGrip: GripDescriptor = {
102	      id: `${wall.id}:start`,
103	      positionMm: start,
104	      shape: 'square',
105	      axis: 'free',
106	      hint: 'Drag start endpoint',
107	      onDrag: (delta) => ({
108	        kind: 'wall',
109	        id: wall.id,
110	        start: { xMm: start.xMm + delta.xMm, yMm: start.yMm + delta.yMm },
111	        end,
112	        thicknessMm: wall.thicknessMm,
113	      }),
114	      onCommit: (delta) => ({
115	        type: 'moveWallEndpoints',
116	        wallId: wall.id,
117	        start: { xMm: start.xMm + delta.xMm, yMm: start.yMm + delta.yMm },
118	        end: { xMm: end.xMm, yMm: end.yMm },
119	      }),
120	      onNumericOverride: (absoluteMm) => {
121	        // Interpret typed value as wall length anchored at `end`,
122	        // direction from `end` toward original `start`.
123	        const dirX = start.xMm - end.xMm;
124	        const dirY = start.yMm - end.yMm;
125	        const len = Math.hypot(dirX, dirY) || 1;
126	        return {
127	          type: 'moveWallEndpoints',
128	          wallId: wall.id,
129	          start: {
130	            xMm: end.xMm + (dirX / len) * absoluteMm,
131	            yMm: end.yMm + (dirY / len) * absoluteMm,
132	          },
133	          end: { xMm: end.xMm, yMm: end.yMm },
134	        };
135	      },
136	    };
137	
138	    const endGrip: GripDescriptor = {
139	      id: `${wall.id}:end`,
140	      positionMm: end,
141	      shape: 'square',
142	      axis: 'free',
143	      hint: 'Drag end endpoint',
144	      onDrag: (delta) => ({
145	        kind: 'wall',
146	        id: wall.id,
147	        start,
148	        end: { xMm: end.xMm + delta.xMm, yMm: end.yMm + delta.yMm },
149	        thicknessMm: wall.thicknessMm,
150	      }),
151	      onCommit: (delta) => ({
152	        type: 'moveWallEndpoints',
153	        wallId: wall.id,
154	        start: { xMm: start.xMm, yMm: start.yMm },
155	        end: { xMm: end.xMm + delta.xMm, yMm: end.yMm + delta.yMm },
156	      }),
157	      onNumericOverride: (absoluteMm) => {
158	        // Wall length anchored at `start`, direction toward original `end`.
159	        const dirX = end.xMm - start.xMm;
160	        const dirY = end.yMm - start.yMm;
161	        const len = Math.hypot(dirX, dirY) || 1;
162	        return {
163	          type: 'moveWallEndpoints',
164	          wallId: wall.id,
165	          start: { xMm: start.xMm, yMm: start.yMm },
166	          end: {
167	            xMm: start.xMm + (dirX / len) * absoluteMm,
168	            yMm: start.yMm + (dirY / len) * absoluteMm,
169	          },
170	        };
171	      },
172	    };
173	
174	    const moveGrip: GripDescriptor = {
175	      id: `${wall.id}:move`,
176	      positionMm: mid,
177	      shape: 'circle',
178	      axis: 'free',
179	      hint: 'Drag to move wall',
180	      onDrag: (delta) => ({
181	        kind: 'wall',
182	        id: wall.id,
183	        start: { xMm: start.xMm + delta.xMm, yMm: start.yMm + delta.yMm },
184	        end: { xMm: end.xMm + delta.xMm, yMm: end.yMm + delta.yMm },
185	        thicknessMm: wall.thicknessMm,
186	      }),
187	      onCommit: (delta) => ({
188	        type: 'moveWallDelta',
189	        wallId: wall.id,
190	        dxMm: delta.xMm,
191	        dyMm: delta.yMm,
192	      }),
193	      onNumericOverride: (absoluteMm) => {
194	        // Translate the wall by `absoluteMm` along its normal — the
195	        // canonical use of a midpoint grip with a typed override.
196	        return {
197	          type: 'moveWallDelta',
198	          wallId: wall.id,
199	          dxMm: n.xMm * absoluteMm,
200	          dyMm: n.yMm * absoluteMm,
201	        };
202	      },
203	    };
204	
205	    const thicknessGrip: GripDescriptor = {
206	      id: `${wall.id}:thickness`,
207	      positionMm: thicknessHandlePos,
208	      shape: 'arrow',
209	      axis: 'normal_to_element',
210	      hint: 'Drag to change thickness',
211	      onDrag: (delta) => {
212	        const projected = projectOntoNormal(delta, n);
213	        const nextThickness = Math.max(20, wall.thicknessMm + 2 * projected);
214	        return {
215	          kind: 'wall',
216	          id: wall.id,
217	          start,
218	          end,
219	          thicknessMm: nextThickness,
220	        };
221	      },
222	      onCommit: (delta) => {
223	        const projected = projectOntoNormal(delta, n);
224	        const nextThickness = Math.max(20, wall.thicknessMm + 2 * projected);
225	        return {
226	          type: 'updateElementProperty',
227	          elementId: wall.id,
228	          key: 'thicknessMm',
229	          value: nextThickness,
230	        };
231	      },
232	      onNumericOverride: (absoluteMm) => ({
233	        type: 'updateElementProperty',
234	        elementId: wall.id,
235	        key: 'thicknessMm',
236	        value: Math.max(20, absoluteMm),
237	      }),
238	    };
239	
240	    return [startGrip, endGrip, moveGrip, thicknessGrip];
241	  },
242	};
243	
244	/** Convenience — single entry point used by PlanCanvas to look up the
245	 *  provider for a given element kind. */
246	export function gripsFor(element: Element, context: PlanContext = {}): GripDescriptor[] {
247	  if (element.kind === 'wall') return wallGripProvider.grips(element, context);
248	  return [];
249	}
250	
251	export { lengthMm, midpoint, unitNormal };
252

