1	/**
2	 * EDT-01 — temporary dimension protocol.
3	 *
4	 * For a selected element, emit dimension hints to the nearest
5	 * neighbour in each cardinal direction. The plan canvas paints the
6	 * targets as faint blue lines with a small lock icon. Clicking a
7	 * target persists the temp dim as a real `dimension` element. The
8	 * lock icon's toggle handler renders, but commits a no-op until
9	 * EDT-02 lands the constraint engine — see the `onLockToggle`
10	 * comment.
11	 */
12	import type { Element, XY } from '@bim-ai/core';
13	
14	import { type GripCommand } from './gripProtocol';
15	
16	export type Wall = Extract<Element, { kind: 'wall' }>;
17	
18	export type TempDimDirection = 'x' | 'y';
19	
20	export interface TempDimTarget {
21	  id: string;
22	  fromMm: XY;
23	  toMm: XY;
24	  direction: TempDimDirection;
25	  /** Distance the dim measures (for the readout label). */
26	  distanceMm: number;
27	  /** Click → persist as a real dimension element. */
28	  onClick: () => GripCommand;
29	  /** Lock icon click. EDT-02 territory: renders the icon now but
30	   *  emits a no-op marker so callers can toast "Constraint locks land
31	   *  in EDT-02" rather than silently swallow the click. */
32	  onLockToggle: () => GripCommand;
33	}
34	
35	function midpoint(a: XY, b: XY): XY {
36	  return { xMm: (a.xMm + b.xMm) / 2, yMm: (a.yMm + b.yMm) / 2 };
37	}
38	
39	function isWall(el: Element): el is Wall {
40	  return el.kind === 'wall';
41	}
42	
43	interface NeighbourSearchOpts {
44	  /** Active level — neighbours on other levels are excluded. */
45	  levelId?: string;
46	  /** Maximum search radius before we stop emitting a dim target. */
47	  maxDistanceMm?: number;
48	}
49	
50	/** Find the nearest wall mid-point in each cardinal direction relative
51	 *  to the source wall's mid-point. Returns up to four candidates
52	 *  (left / right / above / below); directions with no neighbour are
53	 *  silently dropped. */
54	export function wallNeighbours(
55	  source: Wall,
56	  elements: Record<string, Element>,
57	  opts: NeighbourSearchOpts = {},
58	): {
59	  left?: { wall: Wall; distanceMm: number };
60	  right?: { wall: Wall; distanceMm: number };
61	  above?: { wall: Wall; distanceMm: number };
62	  below?: { wall: Wall; distanceMm: number };
63	} {
64	  const ref = midpoint(source.start, source.end);
65	  const max = opts.maxDistanceMm ?? Number.POSITIVE_INFINITY;
66	  let left: { wall: Wall; distanceMm: number } | undefined;
67	  let right: { wall: Wall; distanceMm: number } | undefined;
68	  let above: { wall: Wall; distanceMm: number } | undefined;
69	  let below: { wall: Wall; distanceMm: number } | undefined;
70	  for (const el of Object.values(elements)) {
71	    if (!isWall(el)) continue;
72	    if (el.id === source.id) continue;
73	    if (opts.levelId && el.levelId !== opts.levelId) continue;
74	    const m = midpoint(el.start, el.end);
75	    const dx = m.xMm - ref.xMm;
76	    const dy = m.yMm - ref.yMm;
77	    if (Math.abs(dx) > Math.abs(dy)) {
78	      // Predominantly horizontal offset — left or right neighbour.
79	      const distance = Math.abs(dx);
80	      if (distance > max) continue;
81	      if (dx < 0) {
82	        if (!left || distance < left.distanceMm) left = { wall: el, distanceMm: distance };
83	      } else if (dx > 0) {
84	        if (!right || distance < right.distanceMm) right = { wall: el, distanceMm: distance };
85	      }
86	    } else if (Math.abs(dy) > 0) {
87	      const distance = Math.abs(dy);
88	      if (distance > max) continue;
89	      if (dy < 0) {
90	        if (!above || distance < above.distanceMm) above = { wall: el, distanceMm: distance };
91	      } else if (dy > 0) {
92	        if (!below || distance < below.distanceMm) below = { wall: el, distanceMm: distance };
93	      }
94	    }
95	  }
96	  return { left, right, above, below };
97	}
98	
99	/** Build the full set of temp-dim targets for a selected wall. The
100	 *  click handlers commit `createDimension` against the active level;
101	 *  the lock handler emits an EDT-02 placeholder advisory. */
102	export function wallTempDimensions(
103	  source: Wall,
104	  elements: Record<string, Element>,
105	  opts: NeighbourSearchOpts = {},
106	): TempDimTarget[] {
107	  const neighbours = wallNeighbours(source, elements, opts);
108	  const ref = midpoint(source.start, source.end);
109	  const lvlId = source.levelId;
110	  const targets: TempDimTarget[] = [];
111	
112	  const push = (direction: TempDimDirection, suffix: string, other: XY, distanceMm: number) => {
113	    const fromMm = { xMm: ref.xMm, yMm: ref.yMm };
114	    const toMm = { xMm: other.xMm, yMm: other.yMm };
115	    targets.push({
116	      id: `${source.id}:tempdim:${suffix}`,
117	      fromMm,
118	      toMm,
119	      direction,
120	      distanceMm,
121	      onClick: () => ({
122	        type: 'createDimension',
123	        levelId: lvlId,
124	        aMm: fromMm,
125	        bMm: toMm,
126	        offsetMm: { xMm: 0, yMm: 0 },
127	      }),
128	      onLockToggle: () => ({
129	        // EDT-02 territory — render the icon but emit a no-op so the
130	        // canvas can show a tooltip instead of silently swallowing the
131	        // click. Workspace consumers should match `type` to skip dispatch.
132	        type: 'tempDimLockToggleNoop',
133	        elementId: source.id,
134	        suffix,
135	        message: 'Constraint locks land in EDT-02',
