"""EDT-02 — per-rule evaluators for project-level geometric locks.

After every command apply, the engine calls `evaluate_constraint_locks`
to check each `constraint` element's rule against the candidate state.
Violations surface as `constraint_violation` advisories with severity
`error`, blocking the commit so the user gets the Revit-feel hard
constraint behaviour the EDT-02 spec calls for.

This module is deliberately kept self-contained — the existing
`constraints.py` advisor pipeline imports a single function from here
to merge constraint-lock violations into its violation list.
"""

from __future__ import annotations

import math
from typing import TYPE_CHECKING

if TYPE_CHECKING:  # pragma: no cover - only used by typecheckers
    from bim_ai.constraints import Violation
    from bim_ai.elements import (
        ConstraintElem,
        ConstraintRef,
        Element,
        WallElem,
    )


def _wall_unit_dir(wall: WallElem) -> tuple[float, float] | None:
    dx = wall.end.x_mm - wall.start.x_mm
    dy = wall.end.y_mm - wall.start.y_mm
    length = math.hypot(dx, dy)
    if length < 1e-9:
        return None
    return (dx / length, dy / length)


def _wall_length_mm(wall: WallElem) -> float:
    dx = wall.end.x_mm - wall.start.x_mm
    dy = wall.end.y_mm - wall.start.y_mm
    return math.hypot(dx, dy)


def _wall_anchor(wall: WallElem, anchor: str) -> tuple[float, float]:
    if anchor == "start":
        return (wall.start.x_mm, wall.start.y_mm)
    if anchor == "end":
        return (wall.end.x_mm, wall.end.y_mm)
    # mid / center fall through to midpoint.
    return (
        (wall.start.x_mm + wall.end.x_mm) / 2.0,
        (wall.start.y_mm + wall.end.y_mm) / 2.0,
    )


def _ref_centroid(
    ref: ConstraintRef, elements: dict[str, Element]
) -> tuple[float, float] | None:
    """Resolve a single ref to a 2D world-space anchor point."""
    from bim_ai.elements import WallElem  # local import: avoids cycle

    el = elements.get(ref.element_id)
    if el is None:
        return None
    if isinstance(el, WallElem):
        return _wall_anchor(el, ref.anchor)
    return None


def _refs_centroid(
    refs: list[ConstraintRef], elements: dict[str, Element]
) -> tuple[float, float] | None:
    points: list[tuple[float, float]] = []
    for ref in refs:
        pt = _ref_centroid(ref, elements)
        if pt is None:
            return None
        points.append(pt)
    if not points:
        return None
    sx = sum(p[0] for p in points) / len(points)
    sy = sum(p[1] for p in points) / len(points)
    return (sx, sy)


def _ref_walls(
    refs: list[ConstraintRef], elements: dict[str, Element]
) -> list[WallElem] | None:
    from bim_ai.elements import WallElem  # local import: avoids cycle

    walls: list[WallElem] = []
    for ref in refs:
        el = elements.get(ref.element_id)
        if not isinstance(el, WallElem):
            return None
        walls.append(el)
    return walls if walls else None


def _evaluate_one(
    constraint: ConstraintElem, elements: dict[str, Element]
) -> Violation | None:
    """Evaluate a single constraint, returning a Violation if it fails."""
    from bim_ai.constraints import Violation  # local import: avoids cycle

    rule = constraint.rule
    tol = max(constraint.tolerance_mm, 1e-6)

    if rule == "equal_distance":
        if constraint.locked_value_mm is None:
            return None  # author error — silently ignore here.
        a = _refs_centroid(constraint.refs_a, elements)
        b = _refs_centroid(constraint.refs_b, elements)
        if a is None or b is None:
            return _missing_ref_violation(constraint)
        actual = math.hypot(b[0] - a[0], b[1] - a[1])
        if abs(actual - constraint.locked_value_mm) > tol:
            return Violation(
                rule_id="constraint_violation",
                severity="error",
                message=(
                    f"Locked equal_distance ({constraint.locked_value_mm:.0f}mm) "
                    f"violated (now {actual:.0f}mm)."
                ),
                element_ids=_violation_element_ids(constraint),
                blocking=True,
            )
        return None

    if rule == "equal_length":
        walls_a = _ref_walls(constraint.refs_a, elements)
        walls_b = _ref_walls(constraint.refs_b, elements)
        if walls_a is None or walls_b is None:
            return _missing_ref_violation(constraint)
        avg_a = sum(_wall_length_mm(w) for w in walls_a) / len(walls_a)
        avg_b = sum(_wall_length_mm(w) for w in walls_b) / len(walls_b)
        if abs(avg_a - avg_b) > tol:
            return Violation(
                rule_id="constraint_violation",
                severity="error",
                message=(
                    f"Locked equal_length violated "
                    f"(group A {avg_a:.0f}mm vs group B {avg_b:.0f}mm)."
                ),
                element_ids=_violation_element_ids(constraint),
                blocking=True,
            )
        return None

    if rule in ("parallel", "perpendicular"):
        walls_a = _ref_walls(constraint.refs_a, elements)
        walls_b = _ref_walls(constraint.refs_b, elements)
        if walls_a is None or walls_b is None:
            return _missing_ref_violation(constraint)
        # Compare the *first* wall of each group; multi-wall groups
        # fall through to a pairwise check against group A's leader.
        leader_a = _wall_unit_dir(walls_a[0])
        if leader_a is None:
            return None
        # Tolerance is in degrees here — convert mm tolerance to angular
        # using a 1m baseline so 1mm ≈ 0.057°. Keeps the same author API.
        ang_tol_rad = max(math.atan2(tol, 1000.0), math.radians(0.05))
        for w in walls_b:
            d = _wall_unit_dir(w)
            if d is None:
                continue
            cross = leader_a[0] * d[1] - leader_a[1] * d[0]
            dot = leader_a[0] * d[0] + leader_a[1] * d[1]
            if rule == "parallel":
                # Parallel: |cross| ≈ 0
                if abs(cross) > math.sin(ang_tol_rad):
                    return Violation(
                        rule_id="constraint_violation",
                        severity="error",
                        message="Locked parallel constraint violated (walls no longer parallel).",
                        element_ids=_violation_element_ids(constraint),
                        blocking=True,
                    )
            else:  # perpendicular
                # Perpendicular: |dot| ≈ 0
                if abs(dot) > math.sin(ang_tol_rad):
                    return Violation(
                        rule_id="constraint_violation",
                        severity="error",
                        message="Locked perpendicular constraint violated.",
                        element_ids=_violation_element_ids(constraint),
                        blocking=True,
                    )
        return None

    if rule == "collinear":
        walls = _ref_walls([*constraint.refs_a, *constraint.refs_b], elements)
        if walls is None or len(walls) < 2:
            return _missing_ref_violation(constraint)
        leader = walls[0]
        d = _wall_unit_dir(leader)
        if d is None:
            return None
        ax, ay = leader.start.x_mm, leader.start.y_mm
        # Normal of the leader's direction line:
        nx, ny = -d[1], d[0]
        for w in walls[1:]:
            for px, py in (
                (w.start.x_mm, w.start.y_mm),
                (w.end.x_mm, w.end.y_mm),
            ):
                offset = (px - ax) * nx + (py - ay) * ny
                if abs(offset) > tol:
                    return Violation(
                        rule_id="constraint_violation",
                        severity="error",
                        message=(
                            "Locked collinear constraint violated "
                            f"(point off-axis by {offset:.0f}mm)."
                        ),
                        element_ids=_violation_element_ids(constraint),
                        blocking=True,
                    )
        return None

    return None


def _missing_ref_violation(constraint: ConstraintElem) -> Violation:
    from bim_ai.constraints import Violation

    return Violation(
        rule_id="constraint_violation",
        severity="error",
        message=(
            f"Constraint {constraint.id} references an element kind that "
            "this rule cannot evaluate (or is missing)."
        ),
        element_ids=_violation_element_ids(constraint),
        blocking=True,
    )


def _violation_element_ids(constraint: ConstraintElem) -> list[str]:
    return sorted(
        {
            constraint.id,
            *[r.element_id for r in constraint.refs_a],
            *[r.element_id for r in constraint.refs_b],
        }
    )


def evaluate_constraint_locks(
    elements: dict[str, Element],
) -> list[Violation]:
    """Evaluate every `constraint` element. Returns blocking violations."""
    from bim_ai.elements import ConstraintElem  # local import: avoids cycle

    out: list[Violation] = []
    for el in elements.values():
        if isinstance(el, ConstraintElem):
            v = _evaluate_one(el, elements)
            if v is not None:
                out.append(v)
    return out

