/** EDT-02 — find an existing `equal_distance` constraint between two
 *  source elements (matched on the unordered pair of element ids). */
export function findEqualDistanceLock(
  elementsById: Record<string, Element>,
  aElementId: string,
  bElementId: string,
): ConstraintElem | undefined {
  const target = new Set([aElementId, bElementId]);
  for (const el of Object.values(elementsById)) {
    if (el.kind !== 'constraint') continue;
    if (el.rule !== 'equal_distance') continue;
    if (el.refsA.length !== 1 || el.refsB.length !== 1) continue;
    const ids = new Set([el.refsA[0]!.elementId, el.refsB[0]!.elementId]);
    if (ids.size !== target.size) continue;
    let same = true;
    for (const id of target) if (!ids.has(id)) same = false;
    if (same) return el;
  }
  return undefined;
}

/** Build the full set of temp-dim targets for a selected wall. The
 *  click handlers commit `createDimension` against the active level;
 *  the lock handler authors / removes an `equal_distance` constraint
 *  (EDT-02). */
