        }
        return {
          type: 'createConstraint',
          rule: 'equal_distance',
          refsA: [{ elementId: source.id, anchor: 'center' }],
          refsB: [{ elementId: otherElementId, anchor: 'center' }],
          lockedValueMm: distanceMm,
        };
      },
    });
  };

  if (neighbours.left) {
    const m = midpoint(neighbours.left.wall.start, neighbours.left.wall.end);
    push('x', 'left', m, neighbours.left.distanceMm, neighbours.left.wall.id);
