/**
 * EDT-01 — temporary dimension protocol.
 *
 * For a selected element, emit dimension hints to the nearest
 * neighbour in each cardinal direction. The plan canvas paints the
 * targets as faint blue lines with a small lock icon. Clicking a
 * target persists the temp dim as a real `dimension` element. The
 * lock icon's toggle handler renders, but commits a no-op until
 * EDT-02 lands the constraint engine — see the `onLockToggle`
 * comment.
 */
import type { Element, XY } from '@bim-ai/core';

import { type GripCommand } from './gripProtocol';

export type Wall = Extract<Element, { kind: 'wall' }>;
export type ConstraintElem = Extract<Element, { kind: 'constraint' }>;

export type TempDimDirection = 'x' | 'y';

export interface TempDimTarget {
  id: string;
  fromMm: XY;
  toMm: XY;
  direction: TempDimDirection;
  /** Distance the dim measures (for the readout label). */
  distanceMm: number;
  /** EDT-02 — set when an existing `constraint` element already locks
   *  the distance between this temp-dim's two source elements. */
  lockedConstraintId?: string;
  /** EDT-02 — anchored source-element ids for both ends of the dim;
   *  used by the lock toggle to author a `createConstraint` that
   *  references the right walls. */
  refElementIds?: { a: string; b: string };
  /** Click → persist as a real dimension element. */
  onClick: () => GripCommand;
  /** EDT-02 — lock icon click. When unlocked, returns a
   *  `createConstraint` command (`equal_distance` rule) wired to the
   *  current pair of source elements + measured distance. When locked,
   *  returns a `deleteElement` command targeting the existing lock. */
  onLockToggle: () => GripCommand;
}

function midpoint(a: XY, b: XY): XY {
  return { xMm: (a.xMm + b.xMm) / 2, yMm: (a.yMm + b.yMm) / 2 };
}

function isWall(el: Element): el is Wall {
  return el.kind === 'wall';
}

interface NeighbourSearchOpts {
  /** Active level — neighbours on other levels are excluded. */
  levelId?: string;
  /** Maximum search radius before we stop emitting a dim target. */
  maxDistanceMm?: number;
}

/** Find the nearest wall mid-point in each cardinal direction relative
 *  to the source wall's mid-point. Returns up to four candidates
 *  (left / right / above / below); directions with no neighbour are
 *  silently dropped. */
export function wallNeighbours(
  source: Wall,
  elements: Record<string, Element>,
  opts: NeighbourSearchOpts = {},
): {
  left?: { wall: Wall; distanceMm: number };
  right?: { wall: Wall; distanceMm: number };
  above?: { wall: Wall; distanceMm: number };
  below?: { wall: Wall; distanceMm: number };
} {
  const ref = midpoint(source.start, source.end);
  const max = opts.maxDistanceMm ?? Number.POSITIVE_INFINITY;
  let left: { wall: Wall; distanceMm: number } | undefined;
  let right: { wall: Wall; distanceMm: number } | undefined;
  let above: { wall: Wall; distanceMm: number } | undefined;
  let below: { wall: Wall; distanceMm: number } | undefined;
  for (const el of Object.values(elements)) {
    if (!isWall(el)) continue;
    if (el.id === source.id) continue;
    if (opts.levelId && el.levelId !== opts.levelId) continue;
    const m = midpoint(el.start, el.end);
    const dx = m.xMm - ref.xMm;
    const dy = m.yMm - ref.yMm;
    if (Math.abs(dx) > Math.abs(dy)) {
      // Predominantly horizontal offset — left or right neighbour.
      const distance = Math.abs(dx);
      if (distance > max) continue;
      if (dx < 0) {
        if (!left || distance < left.distanceMm) left = { wall: el, distanceMm: distance };
      } else if (dx > 0) {
        if (!right || distance < right.distanceMm) right = { wall: el, distanceMm: distance };
      }
    } else if (Math.abs(dy) > 0) {
      const distance = Math.abs(dy);
      if (distance > max) continue;
      if (dy < 0) {
        if (!above || distance < above.distanceMm) above = { wall: el, distanceMm: distance };
      } else if (dy > 0) {
        if (!below || distance < below.distanceMm) below = { wall: el, distanceMm: distance };
      }
    }
  }
  return { left, right, above, below };
}

/** Build the full set of temp-dim targets for a selected wall. The
 *  click handlers commit `createDimension` against the active level;
 *  the lock handler emits an EDT-02 placeholder advisory. */
export function wallTempDimensions(
  source: Wall,
  elements: Record<string, Element>,
  opts: NeighbourSearchOpts = {},
): TempDimTarget[] {
  const neighbours = wallNeighbours(source, elements, opts);
  const ref = midpoint(source.start, source.end);
  const lvlId = source.levelId;
  const targets: TempDimTarget[] = [];

  const push = (direction: TempDimDirection, suffix: string, other: XY, distanceMm: number) => {
    const fromMm = { xMm: ref.xMm, yMm: ref.yMm };
    const toMm = { xMm: other.xMm, yMm: other.yMm };
    targets.push({
      id: `${source.id}:tempdim:${suffix}`,
      fromMm,
      toMm,
      direction,
      distanceMm,
      onClick: () => ({
        type: 'createDimension',
        levelId: lvlId,
        aMm: fromMm,
        bMm: toMm,
        offsetMm: { xMm: 0, yMm: 0 },
      }),
      onLockToggle: () => ({
        // EDT-02 territory — render the icon but emit a no-op so the
        // canvas can show a tooltip instead of silently swallowing the
        // click. Workspace consumers should match `type` to skip dispatch.
        type: 'tempDimLockToggleNoop',
        elementId: source.id,
        suffix,
        message: 'Constraint locks land in EDT-02',
      }),
    });
  };

  if (neighbours.left) {
    const m = midpoint(neighbours.left.wall.start, neighbours.left.wall.end);
    push('x', 'left', m, neighbours.left.distanceMm);
  }
  if (neighbours.right) {
    const m = midpoint(neighbours.right.wall.start, neighbours.right.wall.end);
    push('x', 'right', m, neighbours.right.distanceMm);
  }
  if (neighbours.above) {
    const m = midpoint(neighbours.above.wall.start, neighbours.above.wall.end);
    push('y', 'above', m, neighbours.above.distanceMm);
  }
  if (neighbours.below) {
    const m = midpoint(neighbours.below.wall.start, neighbours.below.wall.end);
    push('y', 'below', m, neighbours.below.distanceMm);
  }

  return targets;
}

/** Convenience entry point — returns dim targets for the given
 *  element kind, falling back to an empty list for kinds not yet
 *  wired by EDT-01. */
export function tempDimensionsFor(
  element: Element,
  elements: Record<string, Element>,
  opts: NeighbourSearchOpts = {},
): TempDimTarget[] {
  if (element.kind === 'wall')
    return wallTempDimensions(element, elements, { levelId: element.levelId, ...opts });
  return [];
}

/**
 * EDT-01 — grip + temp-dimension overlay.
 *
 * 2D HTML/SVG overlay rendered above the Three.js canvas. The grip
 * shapes (square / circle / arrow) sit on top of the elements; the
 * temp-dimension layer paints faint blue lines toward the nearest
 * neighbours with a small lock chip. Pure presentational — pointer
 * handlers are passed in by `PlanCanvas`.
 */
import type { CSSProperties, MouseEvent as ReactMouseEvent } from 'react';

import type { GripDescriptor } from './gripProtocol';
import type { TempDimTarget } from './tempDimensions';

export interface ScreenPoint {
  pxX: number;
  pxY: number;
}

export interface GripLayerProps {
  grips: GripDescriptor[];
  worldToScreen: (xy: { xMm: number; yMm: number }) => ScreenPoint;
  onGripPointerDown: (
    grip: GripDescriptor,
    ev: ReactMouseEvent<HTMLDivElement> | PointerEvent,
  ) => void;
  /** Live draft preview while a wall grip is being dragged. */
  draftWall?: { start: { xMm: number; yMm: number }; end: { xMm: number; yMm: number } } | null;
  /** Active grip id — paints a slightly emphasised handle so the user
   *  can see which grip is being dragged. */
  activeGripId?: string | null;
}

const GRIP_PX = 12;

function gripStyle(
  pos: ScreenPoint,
  shape: GripDescriptor['shape'],
  active: boolean,
): CSSProperties {
  const half = GRIP_PX / 2;
  const base: CSSProperties = {
    position: 'absolute',
    left: pos.pxX - half,
    top: pos.pxY - half,
    width: GRIP_PX,
    height: GRIP_PX,
    pointerEvents: 'auto',
    cursor: shape === 'arrow' ? 'ew-resize' : 'grab',
    background: active ? 'rgba(252,211,77,0.35)' : 'rgba(252,211,77,0.15)',
    border: '1.5px solid #fcd34d',
    boxSizing: 'border-box',
    touchAction: 'none',
  };
  if (shape === 'circle') {
    base.borderRadius = '50%';
  }
  if (shape === 'arrow') {
    // Diamond — distinguishes it from the squares without a sprite.
    base.transform = 'rotate(45deg)';
  }
  return base;
}

export function GripLayer({
  grips,
  worldToScreen,
  onGripPointerDown,
  draftWall,
  activeGripId,
}: GripLayerProps) {
  if (grips.length === 0 && !draftWall) return null;
  return (
    <div
      data-testid="grip-layer"
      style={{
        position: 'absolute',
        inset: 0,
        pointerEvents: 'none',
      }}
    >
      {draftWall && (
        <DraftWallPreview
          start={worldToScreen(draftWall.start)}
          end={worldToScreen(draftWall.end)}
        />
      )}
      {grips.map((g) => {
        const pos = worldToScreen(g.positionMm);
        return (
          <div
            key={g.id}
            data-testid={`grip-${g.id}`}
            data-grip-shape={g.shape}
            data-grip-axis={g.axis}
            title={g.hint ?? g.id}
            style={gripStyle(pos, g.shape, activeGripId === g.id)}
            onPointerDown={(ev) => {
              ev.stopPropagation();
              onGripPointerDown(g, ev);
            }}
          />
        );
      })}
    </div>
  );
}

function DraftWallPreview({ start, end }: { start: ScreenPoint; end: ScreenPoint }) {
  const minX = Math.min(start.pxX, end.pxX) - 4;
  const minY = Math.min(start.pxY, end.pxY) - 4;
  const maxX = Math.max(start.pxX, end.pxX) + 4;
  const maxY = Math.max(start.pxY, end.pxY) + 4;
  const w = Math.max(1, maxX - minX);
  const h = Math.max(1, maxY - minY);
  return (
    <svg
      data-testid="grip-draft-preview"
      style={{ position: 'absolute', left: minX, top: minY, pointerEvents: 'none' }}
      width={w}
      height={h}
      viewBox={`${minX} ${minY} ${w} ${h}`}
    >
      <line
        x1={start.pxX}
        y1={start.pxY}
        x2={end.pxX}
        y2={end.pxY}
        stroke="#fcd34d"
        strokeWidth={2}
        strokeDasharray="6 4"
      />
    </svg>
  );
}

/* ─── Temp-dimension layer ────────────────────────────────────────── */

export interface TempDimLayerProps {
  targets: TempDimTarget[];
  worldToScreen: (xy: { xMm: number; yMm: number }) => ScreenPoint;
  onTargetClick: (target: TempDimTarget) => void;
  onLockClick: (target: TempDimTarget) => void;
}

function formatMm(mm: number): string {
  if (mm >= 1000) return `${(mm / 1000).toFixed(2)} m`;
  return `${Math.round(mm)} mm`;
}

export function TempDimLayer({
  targets,
  worldToScreen,
  onTargetClick,
  onLockClick,
}: TempDimLayerProps) {
  if (targets.length === 0) return null;
  return (
    <div
      data-testid="temp-dim-layer"
      style={{
        position: 'absolute',
        inset: 0,
        pointerEvents: 'none',
      }}
    >
      {targets.map((t) => {
        const a = worldToScreen(t.fromMm);
        const b = worldToScreen(t.toMm);
        const cx = (a.pxX + b.pxX) / 2;
        const cy = (a.pxY + b.pxY) / 2;
        const minX = Math.min(a.pxX, b.pxX) - 24;
        const minY = Math.min(a.pxY, b.pxY) - 24;
        const maxX = Math.max(a.pxX, b.pxX) + 24;
        const maxY = Math.max(a.pxY, b.pxY) + 24;
        const w = Math.max(1, maxX - minX);
        const h = Math.max(1, maxY - minY);
        return (
          <div key={t.id} data-testid={`temp-dim-${t.id}`}>
            <svg
              style={{
                position: 'absolute',
                left: minX,
                top: minY,
                pointerEvents: 'none',
              }}
              width={w}
              height={h}
              viewBox={`${minX} ${minY} ${w} ${h}`}
            >
              <line
                x1={a.pxX}
                y1={a.pxY}
                x2={b.pxX}
                y2={b.pxY}
                stroke="#7dd3fc"
                strokeOpacity={0.55}
                strokeWidth={1}
                strokeDasharray="4 3"
              />
            </svg>
            <button
              type="button"
              data-testid={`temp-dim-readout-${t.id}`}
              onClick={() => onTargetClick(t)}
              style={{
                position: 'absolute',
                left: cx - 30,
                top: cy - 10,
                width: 60,
                height: 20,
                pointerEvents: 'auto',
                cursor: 'pointer',
                background: 'rgba(20,28,42,0.75)',
                color: '#7dd3fc',
                fontSize: 10,
                fontFamily:
                  'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Monaco, Consolas, monospace',
                border: '1px solid rgba(125,211,252,0.4)',
                borderRadius: 3,
              }}
              title="Click to convert to a persistent dimension"
            >
              {formatMm(t.distanceMm)}
            </button>
            <button
              type="button"
              data-testid={`temp-dim-lock-${t.id}`}
              onClick={() => onLockClick(t)}
              style={{
                position: 'absolute',
                left: cx + 32,
                top: cy - 10,
                width: 18,
                height: 18,
                pointerEvents: 'auto',
                cursor: 'pointer',
                background: 'rgba(20,28,42,0.75)',
                color: '#7dd3fc',
                fontSize: 11,
                border: '1px solid rgba(125,211,252,0.4)',
                borderRadius: 3,
                lineHeight: '15px',
                padding: 0,
              }}
              title="Constraint locks land in EDT-02"
              aria-label="Toggle dimension lock (EDT-02)"
            >
              🔓
            </button>
          </div>
        );
      })}
    </div>
  );
}

