import { describe, expect, it } from 'vitest';

import type { Element } from '@bim-ai/core';

import {
  findEqualDistanceLock,
  wallTempDimensions,
  type Wall,
} from './tempDimensions';

const SOURCE: Wall = {
  kind: 'wall',
  id: 'src',
  name: 'Wall',
  levelId: 'L1',
  start: { xMm: 0, yMm: 0 },
  end: { xMm: 4000, yMm: 0 },
  thicknessMm: 200,
  heightMm: 2700,
};

function wall(id: string, sx: number, sy: number, ex: number, ey: number): Wall {
  return {
    kind: 'wall',
    id,
    name: id,
    levelId: 'L1',
    start: { xMm: sx, yMm: sy },
    end: { xMm: ex, yMm: ey },
    thicknessMm: 200,
    heightMm: 2700,
  };
}

function constraint(
  id: string,
  ruleA: string,
  ruleB: string,
): Extract<Element, { kind: 'constraint' }> {
  return {
    kind: 'constraint',
    id,
    rule: 'equal_distance',
    refsA: [{ elementId: ruleA, anchor: 'center' }],
    refsB: [{ elementId: ruleB, anchor: 'center' }],
    lockedValueMm: 4000,
  };
}

describe('EDT-02 — temp-dim padlock click commits a constraint', () => {
  it('returns a createConstraint command on first lock click', () => {
    const elements: Record<string, Element> = {
      src: SOURCE,
      neighbour: wall('neighbour', 0, 4000, 4000, 4000),
    };
    const targets = wallTempDimensions(SOURCE, elements);
    const target = targets.find((t) => t.refElementIds?.b === 'neighbour');
    expect(target).toBeDefined();
    expect(target!.lockedConstraintId).toBeUndefined();
    const cmd = target!.onLockToggle();
    expect(cmd).toMatchObject({
      type: 'createConstraint',
      rule: 'equal_distance',
      lockedValueMm: 4000,
    });
    expect(cmd.refsA).toEqual([{ elementId: 'src', anchor: 'center' }]);
    expect(cmd.refsB).toEqual([{ elementId: 'neighbour', anchor: 'center' }]);
  });

  it('detects an existing equal_distance lock and returns deleteElement on click', () => {
    const elements: Record<string, Element> = {
      src: SOURCE,
      neighbour: wall('neighbour', 0, 4000, 4000, 4000),
      lock: constraint('lock', 'src', 'neighbour'),
    };
    const targets = wallTempDimensions(SOURCE, elements);
    const target = targets.find((t) => t.refElementIds?.b === 'neighbour');
    expect(target).toBeDefined();
    expect(target!.lockedConstraintId).toBe('lock');
    const cmd = target!.onLockToggle();
    expect(cmd).toEqual({ type: 'deleteElement', elementId: 'lock' });
  });

  it('matches lock regardless of refsA/refsB order', () => {
    const elements: Record<string, Element> = {
      src: SOURCE,
      neighbour: wall('neighbour', 0, 4000, 4000, 4000),
      // Reversed: refsA references the neighbour, refsB references the source.
      lock: constraint('lock', 'neighbour', 'src'),
    };
    const found = findEqualDistanceLock(elements, 'src', 'neighbour');
    expect(found?.id).toBe('lock');
  });

  it('does not match a lock whose rule is not equal_distance', () => {
    const elements: Record<string, Element> = {
      src: SOURCE,
      neighbour: wall('neighbour', 0, 4000, 4000, 4000),
      par: {
        kind: 'constraint',
        id: 'par',
        rule: 'parallel',
        refsA: [{ elementId: 'src', anchor: 'center' }],
        refsB: [{ elementId: 'neighbour', anchor: 'center' }],
      },
    };
    const found = findEqualDistanceLock(elements, 'src', 'neighbour');
    expect(found).toBeUndefined();
  });
});

