/**
 * EDT-03 — universal 3D grip protocol.
 *
 * Mirror of `plan/gripProtocol.ts` (EDT-01) but in 3D world coordinates.
 * Each provider exposes the in-place manipulation handles for one
 * element kind; the viewport raycasts handles before element pick so
 * grips take hover priority. The runtime in `grip3dRuntime.ts` paints
 * the handles with Three.js LineSegments + Sprite and drives the drag
 * protocol — Esc cancels (revert draft), release commits.
 *
 * Coordinate convention: positions are returned in meters in the
 * viewport's render coordinate space — the viewport already maps the
 * BIM (mm, +Z up) authoring space onto Three's (m, +Y up) render
 * space, and providers compose with that mapping rather than re-
 * implementing it.
 */

import type { Element } from '@bim-ai/core';

/** A draft mutation produced by a 3D grip during drag — used by the
 *  runtime to render a live preview before the command commits. */
export type Draft3dMutation =
  | {
      kind: 'wall_height';
      id: string;
      heightMm: number;
      topOffsetMm?: number;
      baseOffsetMm?: number;
    }
  | {
      kind: 'floor_vertex';
      id: string;
      vertexIndex: number;
      positionMm: { xMm: number; yMm: number };
    }
  | {
      kind: 'roof_ridge';
      id: string;
      ridgeHeightMm: number;
    }
  | {
      kind: 'section_box_corner';
      cornerKey: string;
      positionMeters: { x: number; y: number; z: number };
    }
  | { kind: 'unknown'; id: string };

/** Engine command shape — matches the JSON the
 *  `onSemanticCommand(cmd: Record<string, unknown>)` callback expects. */
export type Grip3dCommand = Record<string, unknown>;

/** Render-space 3D vector (meters, Three.js convention: +Y up). */
export interface Vec3M {
  x: number;
  y: number;
  z: number;
}

export type Grip3dAxis =
  | { kind: 'x' }
  | { kind: 'y' }
  | { kind: 'z' }
  | { kind: 'free' }
  | { kind: 'world'; direction: Vec3M };

export interface Grip3dDescriptor {
  id: string;
  /** Position in render-space meters (the runtime paints handles here). */
  positionMeters: Vec3M;
  /** Drag axis — drives the glowing axis line shown during drag. */
  axis: Grip3dAxis;
  /** Color of the axis glow / handle box. Hex string. */
  colorHex: string;
  /** Tooltip-style hint surfaced near the handle. */
  hint?: string;
  /** Live-preview mutation while dragging. `deltaMeters` is the
   *  cursor offset projected onto `axis` (or free in 3D). */
  onDrag: (deltaMeters: Vec3M) => Draft3dMutation;
  /** Commit-on-release. Returns the engine command. */
  onCommit: (deltaMeters: Vec3M) => Grip3dCommand;
}

export interface Plan3dContext {
  /** Active level id — same purpose as in plan grips. */
  activeLevelId?: string;
  /** All elements, for providers that need cross-element context (e.g.
   *  level lookup for wall heights). */
  elementsById?: Record<string, Element>;
}

export interface Element3dGripProvider<E extends Element> {
  grips(element: E, context: Plan3dContext): Grip3dDescriptor[];
}

/* ─── Provider registry ────────────────────────────────────────────── */

const REGISTRY = new Map<Element['kind'], Element3dGripProvider<Element>>();

/** Register a provider for an element kind. Replaces any existing
 *  provider for the same kind. */
export function register3dGripProvider<K extends Element['kind']>(
  kind: K,
  provider: Element3dGripProvider<Extract<Element, { kind: K }>>,
): void {
  REGISTRY.set(kind, provider as unknown as Element3dGripProvider<Element>);
}

/** Convenience — resolve grips for the given element by kind. */
export function gripsFor3d(
  element: Element,
  context: Plan3dContext = {},
): Grip3dDescriptor[] {
  const provider = REGISTRY.get(element.kind);
  if (!provider) return [];
  return provider.grips(element, context);
}

/** Test helper — list registered kinds. */
export function registered3dGripKinds(): Element['kind'][] {
  return [...REGISTRY.keys()];
}

/** Test helper — clear registry between tests. */
export function _resetGrip3dRegistry(): void {
  REGISTRY.clear();
}

/* ─── Coordinate helpers ───────────────────────────────────────────── */

/** BIM (mm, +Z up) → Three render-space (m, +Y up).
 *  Matches the convention used throughout meshBuilders.ts: BIM (x, y, z)
 *  → Three (x/1000, z/1000, y/1000). Centralised here so providers can
 *  compose without duplicating the swap. */
export function bimMmToRenderM(input: { xMm: number; yMm: number; zMm: number }): Vec3M {
  return {
    x: input.xMm / 1000,
    y: input.zMm / 1000,
    z: input.yMm / 1000,
  };
}

/** Inverse of `bimMmToRenderM`. */
export function renderMToBimMm(input: Vec3M): { xMm: number; yMm: number; zMm: number } {
  return {
    xMm: input.x * 1000,
    yMm: input.z * 1000,
    zMm: input.y * 1000,
  };
}

