/**
 * EDT-03 — element-specific 3D grip providers.
 *
 * Wall: top + bottom edge handles (drag-up grows
 * `topConstraintOffsetMm`, drag-down shrinks `baseConstraintOffsetMm`).
 *
 * Floor: edge-handle drags one vertex of the boundary polygon —
 * geometry follows in real time and the commit emits an
 * `updateElementProperty` with the new boundary array.
 *
 * Roof: ridge handle drags ridge height (Z).
 *
 * Section box: corner handles for free-form cuts (six face handles
 * already exist on `SectionBox.tsx`; this module adds the eight
 * corners).
 */

import type { Element } from '@bim-ai/core';

import {
  bimMmToRenderM,
  type Element3dGripProvider,
  type Grip3dDescriptor,
  register3dGripProvider,
  type Vec3M,
} from './grip3d';

type Wall = Extract<Element, { kind: 'wall' }>;
type Floor = Extract<Element, { kind: 'floor' }>;
type Roof = Extract<Element, { kind: 'roof' }>;
type Level = Extract<Element, { kind: 'level' }>;

const COL_TOP = '#22d3ee'; // cyan — top-edge wall handle
const COL_BASE = '#fb7185'; // rose — base-edge wall handle
const COL_FLOOR = '#fbbf24'; // amber — floor vertex handles
const COL_ROOF = '#a3e635'; // lime — roof ridge handle
const COL_SECTION = '#c084fc'; // purple — section box corners

/* ─── Wall provider ────────────────────────────────────────────────── */

function wallMidMm(wall: Wall): { xMm: number; yMm: number } {
  return {
    xMm: (wall.start.xMm + wall.end.xMm) / 2,
    yMm: (wall.start.yMm + wall.end.yMm) / 2,
  };
}

function wallBaseElevationMm(
  wall: Wall,
  elementsById?: Record<string, Element>,
): number {
  if (!elementsById) return wall.baseConstraintOffsetMm ?? 0;
  const lvl = elementsById[wall.levelId];
  const baseLvl =
    wall.baseConstraintLevelId !== undefined && wall.baseConstraintLevelId !== null
      ? elementsById[wall.baseConstraintLevelId]
      : lvl;
  const elevMm = baseLvl?.kind === 'level' ? (baseLvl as Level).elevationMm : 0;
  return elevMm + (wall.baseConstraintOffsetMm ?? 0);
}

function wallTopElevationMm(
  wall: Wall,
  elementsById?: Record<string, Element>,
): number {
  const baseElev = wallBaseElevationMm(wall, elementsById);
  if (wall.topConstraintLevelId && elementsById) {
    const topLvl = elementsById[wall.topConstraintLevelId];
    if (topLvl?.kind === 'level') {
      return (topLvl as Level).elevationMm + (wall.topConstraintOffsetMm ?? 0);
    }
  }
  return baseElev + (wall.heightMm ?? 0);
}

export const wallGrip3dProvider: Element3dGripProvider<Wall> = {
  grips(wall, context): Grip3dDescriptor[] {
    const mid = wallMidMm(wall);
    const elementsById = context.elementsById;
    const baseElevMm = wallBaseElevationMm(wall, elementsById);
    const topElevMm = wallTopElevationMm(wall, elementsById);
    const topPos = bimMmToRenderM({ xMm: mid.xMm, yMm: mid.yMm, zMm: topElevMm });
    const basePos = bimMmToRenderM({ xMm: mid.xMm, yMm: mid.yMm, zMm: baseElevMm });

    // Capture starting properties so onDrag/onCommit don't drift if the
    // element is mutated mid-drag (e.g. by federation refresh).
    const startTopOffsetMm = wall.topConstraintOffsetMm ?? 0;
    const startBaseOffsetMm = wall.baseConstraintOffsetMm ?? 0;
    const startHeightMm = wall.heightMm ?? 0;

    const topGrip: Grip3dDescriptor = {
      id: `${wall.id}:top`,
      positionMeters: topPos,
      axis: { kind: 'y' },
      colorHex: COL_TOP,
      hint: 'Drag to change top elevation',
      onDrag: (deltaMeters) => {
        const dyMm = deltaMeters.y * 1000;
        if (wall.topConstraintLevelId) {
          return {
            kind: 'wall_height',
            id: wall.id,
            heightMm: startHeightMm,
            topOffsetMm: startTopOffsetMm + dyMm,
          };
        }
        return {
          kind: 'wall_height',
          id: wall.id,
          heightMm: Math.max(50, startHeightMm + dyMm),
        };
      },
      onCommit: (deltaMeters) => {
        const dyMm = deltaMeters.y * 1000;
        if (wall.topConstraintLevelId) {
          return {
            type: 'updateElementProperty',
            elementId: wall.id,
            key: 'topConstraintOffsetMm',
            value: startTopOffsetMm + dyMm,
          };
        }
        return {
          type: 'updateElementProperty',
          elementId: wall.id,
          key: 'heightMm',
          value: Math.max(50, startHeightMm + dyMm),
        };
      },
    };

    const baseGrip: Grip3dDescriptor = {
      id: `${wall.id}:base`,
      positionMeters: basePos,
      axis: { kind: 'y' },
      colorHex: COL_BASE,
      hint: 'Drag to change base elevation',
      onDrag: (deltaMeters) => ({
        kind: 'wall_height',
        id: wall.id,
        heightMm: startHeightMm,
        baseOffsetMm: startBaseOffsetMm + deltaMeters.y * 1000,
      }),
      onCommit: (deltaMeters) => ({
        type: 'updateElementProperty',
        elementId: wall.id,
        key: 'baseConstraintOffsetMm',
        value: startBaseOffsetMm + deltaMeters.y * 1000,
      }),
    };

    return [topGrip, baseGrip];
  },
};

/* ─── Floor provider ───────────────────────────────────────────────── */

export const floorGrip3dProvider: Element3dGripProvider<Floor> = {
  grips(floor, context): Grip3dDescriptor[] {
    const elementsById = context.elementsById;
    const lvl = elementsById?.[floor.levelId];
    const elevMm =
      lvl?.kind === 'level' ? (lvl as Level).elevationMm : 0;
    // Floors render with their top face at level + thickness; pick a Y
    // slightly above the slab so the handle is visible.
    const topMm = elevMm + (floor.thicknessMm ?? 200);
    const grips: Grip3dDescriptor[] = [];
    floor.boundaryMm.forEach((p, i) => {
      grips.push({
        id: `${floor.id}:vertex:${i}`,
        positionMeters: bimMmToRenderM({ xMm: p.xMm, yMm: p.yMm, zMm: topMm }),
        axis: { kind: 'free' },
        colorHex: COL_FLOOR,
        hint: 'Drag to move floor vertex',
        onDrag: (deltaMeters) => ({
          kind: 'floor_vertex',
          id: floor.id,
          vertexIndex: i,
          positionMm: {
            xMm: p.xMm + deltaMeters.x * 1000,
            yMm: p.yMm + deltaMeters.z * 1000,
          },
        }),
        onCommit: (deltaMeters) => {
          const newBoundary = floor.boundaryMm.map((q, qi) =>
            qi === i
              ? {
                  xMm: p.xMm + deltaMeters.x * 1000,
                  yMm: p.yMm + deltaMeters.z * 1000,
                }
              : { xMm: q.xMm, yMm: q.yMm },
          );
          return {
            type: 'updateElementProperty',
            elementId: floor.id,
            key: 'boundaryMm',
            value: newBoundary,
          };
        },
      });
    });
    return grips;
  },
};

/* ─── Roof provider ────────────────────────────────────────────────── */

export const roofGrip3dProvider: Element3dGripProvider<Roof> = {
  grips(roof, context): Grip3dDescriptor[] {
    const elementsById = context.elementsById;
    const lvl =
      roof.referenceLevelId !== undefined
        ? elementsById?.[roof.referenceLevelId]
        : undefined;
    const elevMm = lvl?.kind === 'level' ? (lvl as Level).elevationMm : 0;
    // Centroid of the footprint as the X/Y; ridge height stacks above.
    const fp = roof.footprintMm ?? [];
    if (fp.length === 0) return [];
    const cx = fp.reduce((s, p) => s + p.xMm, 0) / fp.length;
    const cy = fp.reduce((s, p) => s + p.yMm, 0) / fp.length;
    const ridgeHeightMm = Math.max(0, roof.ridgeHeightMm ?? 1500);
    const topMm = elevMm + ridgeHeightMm;
    return [
      {
        id: `${roof.id}:ridge`,
        positionMeters: bimMmToRenderM({ xMm: cx, yMm: cy, zMm: topMm }),
        axis: { kind: 'y' },
        colorHex: COL_ROOF,
        hint: 'Drag to change ridge height',
        onDrag: (deltaMeters) => ({
          kind: 'roof_ridge',
          id: roof.id,
          ridgeHeightMm: Math.max(50, ridgeHeightMm + deltaMeters.y * 1000),
        }),
        onCommit: (deltaMeters) => ({
          type: 'updateElementProperty',
          elementId: roof.id,
          key: 'ridgeHeightMm',
          value: Math.max(50, ridgeHeightMm + deltaMeters.y * 1000),
        }),
      },
    ];
  },
};

/* ─── Section box corner provider ─────────────────────────────────── */

/** Standalone helper — section box is not a project Element so it
 *  doesn't fit the per-Element provider pattern. The runtime calls
 *  this directly when sectionBox is active. */
export function sectionBoxCornerGrips(box: {
  minMeters: Vec3M;
  maxMeters: Vec3M;
}): Grip3dDescriptor[] {
  const out: Grip3dDescriptor[] = [];
  const { minMeters: a, maxMeters: b } = box;
  const corners: { key: string; pos: Vec3M }[] = [
    { key: 'min-min-min', pos: { x: a.x, y: a.y, z: a.z } },
    { key: 'max-min-min', pos: { x: b.x, y: a.y, z: a.z } },
    { key: 'min-max-min', pos: { x: a.x, y: b.y, z: a.z } },
    { key: 'max-max-min', pos: { x: b.x, y: b.y, z: a.z } },
    { key: 'min-min-max', pos: { x: a.x, y: a.y, z: b.z } },
    { key: 'max-min-max', pos: { x: b.x, y: a.y, z: b.z } },
    { key: 'min-max-max', pos: { x: a.x, y: b.y, z: b.z } },
    { key: 'max-max-max', pos: { x: b.x, y: b.y, z: b.z } },
  ];
  for (const c of corners) {
    out.push({
      id: `section:corner:${c.key}`,
      positionMeters: c.pos,
      axis: { kind: 'free' },
      colorHex: COL_SECTION,
      hint: 'Drag to extend section box',
      onDrag: (deltaMeters) => ({
        kind: 'section_box_corner',
        cornerKey: c.key,
        positionMeters: {
          x: c.pos.x + deltaMeters.x,
          y: c.pos.y + deltaMeters.y,
          z: c.pos.z + deltaMeters.z,
        },
      }),
      onCommit: () => ({
        type: 'sectionBoxCornerNoop',
        cornerKey: c.key,
      }),
    });
  }
  return out;
}

/* ─── Auto-registration ────────────────────────────────────────────── */

let registered = false;
export function registerDefaultGrip3dProviders(): void {
  if (registered) return;
  registered = true;
  register3dGripProvider('wall', wallGrip3dProvider);
  register3dGripProvider('floor', floorGrip3dProvider);
  register3dGripProvider('roof', roofGrip3dProvider);
}

/** Test helper — undo registration. */
export function _resetGrip3dProvidersRegistration(): void {
  registered = false;
}

