input.content:
/**
 * EDT-03 — runtime that paints 3D grip handles and drives the
 * pointer/drag protocol against the registered providers.
 *
 * The runtime is deliberately self-contained — `Viewport.tsx` mounts
 * it via `attachGrip3dLayer` once on mount, the layer reads live
 * element state through a callback, and the runtime emits engine
 * commands through a single dispatcher. No global state.
 *
 * Lifecycle:
 *   - `refresh()` — rebuild handles for the current selection.
 *   - `tryPickHandle(ndc)` — runs before element pick; returns the
 *     picked handle id (if any) so the host can short-circuit.
 *   - `beginDrag(handleId, screen)` / `updateDrag(screen)` /
 *     `endDrag(commit)` — drive the drag flow.
 *   - `dispose()` — tear down all THREE objects + listeners.
 */

import * as THREE from 'three';

import type { Element } from '@bim-ai/core';

import {
  bimMmToRenderM as _unused_bim,
  type Draft3dMutation,
  type Grip3dAxis,
  type Grip3dDescriptor,
  gripsFor3d,
  type Vec3M,
} from './grip3d';

void _unused_bim;

const HANDLE_SIZE_M = 0.16;
const AXIS_GLOW_LEN_M = 4;

export interface Grip3dRuntimeOptions {
  scene: THREE.Scene;
  camera: THREE.Camera;
  domElement: HTMLElement;
  /** Read live state on demand — the runtime never caches the
   *  element record. */
  getSelectedElement: () => Element | undefined;
  getElementsById: () => Record<string, Element>;
  /** Dispatcher for the engine command (commit-on-release). */
  dispatchCommand: (cmd: Record<string, unknown>) => void;
}

export interface Grip3dRuntime {
  refresh(): void;
  /** Returns the picked handle id, or null. Call before element pick. */
  tryPickHandle(clientX: number, clientY: number): string | null;
  beginDrag(handleId: string, clientX: number, clientY: number): boolean;
  updateDrag(clientX: number, clientY: number): Draft3dMutation | null;
  endDrag(commit: boolean): void;
  /** Live drag state — for tests + HUD overlays. */
  getDragState():
    | { handleId: string; draft: Draft3dMutation; descriptor: Grip3dDescriptor }
    | null;
  dispose(): void;
}

interface HandleVisual {
  descriptor: Grip3dDescriptor;
  mesh: THREE.Mesh;
}

interface DragState {
  handleId: string;
  descriptor: Grip3dDescriptor;
  startScreen: { x: number; y: number };
  startNdc: THREE.Vector2;
  axisDir: THREE.Vector3;
  /** Distance from camera to handle origin — used to scale screen
   *  delta back into world space. */
  worldDepth: number;
  /** Last computed draft, kept for `getDragState`. */
  lastDraft: Draft3dMutation;
  /** Last delta in world meters. */
  lastDelta: Vec3M;
  /** Glow line for the active axis (only created if axis is non-free). */
  glow: THREE.LineSegments | null;
}

function axisToVec3(axis: Grip3dAxis): THREE.Vector3 {
  switch (axis.kind) {
    case 'x':
      return new THREE.Vector3(1, 0, 0);
    case 'y':
      return new THREE.Vector3(0, 1, 0);
    case 'z':
      return new THREE.Vector3(0, 0, 1);
    case 'free':
      return new THREE.Vector3(0, 1, 0);
    case 'world':
      return new THREE.Vector3(axis.direction.x, axis.direction.y, axis.direction.z).normalize();
  }
}

function colorOf(hex: string): THREE.Color {
  return new THREE.Color(hex);
}

export function attachGrip3dLayer(opts: Grip3dRuntimeOptions): Grip3dRuntime {
  const layer = new THREE.Group();
  layer.name = 'grip3d-layer';
  layer.renderOrder = 999;
  opts.scene.add(layer);

  const handles = new Map<string, HandleVisual>();
  const raycaster = new THREE.Raycaster();
  const ndc = new THREE.Vector2();
  let drag: DragState | null = null;

  function clearHandles() {
    for (const v of handles.values()) {
      layer.remove(v.mesh);
      v.mesh.geometry.dispose();
      (v.mesh.material as THREE.Material).dispose();
    }
    handles.clear();
  }

  function refresh() {
    clearHandles();
    const sel = opts.getSelectedElement();
    if (!sel) return;
    const grips = gripsFor3d(sel, { elementsById: opts.getElementsById() });
    for (const g of grips) {
      const geom = new THREE.BoxGeometry(HANDLE_SIZE_M, HANDLE_SIZE_M, HANDLE_SIZE_M);
      const mat = new THREE.MeshBasicMaterial({
        color: colorOf(g.colorHex),
        depthTest: false,
        transparent: true,
        opacity: 0.92,
      });
      const mesh = new THREE.Mesh(geom, mat);
      mesh.position.set(g.positionMeters.x, g.positionMeters.y, g.positionMeters.z);
      mesh.userData.grip3dHandleId = g.id;
      mesh.renderOrder = 999;
      layer.add(mesh);
      handles.set(g.id, { descriptor: g, mesh });
    }
  }

  function setNdc(clientX: number, clientY: number): boolean {
    const rect = opts.domElement.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) return false;
    ndc.x = ((clientX - rect.left) / rect.width) * 2 - 1;
    ndc.y = -(((clientY - rect.top) / rect.height) * 2 - 1);
    return true;
  }

  function tryPickHandle(clientX: number, clientY: number): string | null {
    if (handles.size === 0) return null;
    if (!setNdc(clientX, clientY)) return null;
    raycaster.setFromCamera(ndc, opts.camera);
    const hits = raycaster.intersectObjects(layer.children, true);
    for (const h of hits) {
      const id = h.object.userData.grip3dHandleId;
      if (typeof id === 'string') return id;
    }
    return null;
  }

  function makeAxisGlow(handlePos: THREE.Vector3, axisDir: THREE.Vector3, hex: string) {
    const a = handlePos.clone().add(axisDir.clone().multiplyScalar(-AXIS_GLOW_LEN_M));
    const b = handlePos.clone().add(axisDir.clone().multiplyScalar(AXIS_GLOW_LEN_M));
    const geom = new THREE.BufferGeometry().setFromPoints([a, b]);
    const mat = new THREE.LineBasicMaterial({
      color: colorOf(hex),
      depthTest: false,
      transparent: true,
      opacity: 0.6,
    });
    const line = new THREE.LineSegments(geom, mat);
    line.renderOrder = 1000;
    return line;
  }

  function beginDrag(handleId: string, clientX: number, clientY: number): boolean {
    const v = handles.get(handleId);
    if (!v) return false;
    if (!setNdc(clientX, clientY)) return false;
    const axisDir = axisToVec3(v.descriptor.axis);
    const handlePos = new THREE.Vector3(
      v.descriptor.positionMeters.x,
      v.descriptor.positionMeters.y,
      v.descriptor.positionMeters.z,
    );
    const cameraPos = new THREE.Vector3();
    opts.camera.getWorldPosition(cameraPos);
    const worldDepth = Math.max(0.5, cameraPos.distanceTo(handlePos));
    let glow: THREE.LineSegments | null = null;
    if (v.descriptor.axis.kind !== 'free') {
      glow = makeAxisGlow(handlePos, axisDir, v.descriptor.colorHex);
      layer.add(glow);
    }
    drag = {
      handleId,
      descriptor: v.descriptor,
      startScreen: { x: clientX, y: clientY },
      startNdc: new THREE.Vector2(ndc.x, ndc.y),
      axisDir,
      worldDepth,
      lastDelta: { x: 0, y: 0, z: 0 },
      lastDraft: v.descriptor.onDrag({ x: 0, y: 0, z: 0 }),
      glow,
    };
    return true;
  }

  function ndcToWorldOffset(currentNdc: THREE.Vector2): Vec3M {
    if (!drag) return { x: 0, y: 0, z: 0 };
    // Approximate world-space delta from screen displacement: project
    // both ndc points onto the plane through the handle perpendicular
    // to the camera direction at depth `worldDepth`.
    const cam = opts.camera as THREE.PerspectiveCamera;
    const fov = cam.isPerspectiveCamera ? (cam.fov * Math.PI) / 180 : 0.5;
    const aspect = cam.isPerspectiveCamera ? cam.aspect : 1;
    const heightAtDepth = cam.isPerspectiveCamera
      ? 2 * Math.tan(fov / 2) * drag.worldDepth
      : 4;
    const widthAtDepth = heightAtDepth * aspect;
    const dndcX = currentNdc.x - drag.startNdc.x;
    const dndcY = currentNdc.y - drag.startNdc.y;
    const dxWorld = (dndcX * widthAtDepth) / 2;
    const dyWorld = (dndcY * heightAtDepth) / 2;
    // Resolve into camera-aligned right / up vectors.
    const right = new THREE.Vector3().setFromMatrixColumn(cam.matrixWorld, 0);
    const up = new THREE.Vector3().setFromMatrixColumn(cam.matrixWorld, 1);
    const offset = right.multiplyScalar(dxWorld).add(up.multiplyScalar(dyWorld));
    if (drag.descriptor.axis.kind !== 'free') {
      // Project onto the axis direction.
      const t = offset.dot(drag.axisDir);
      const projected = drag.axisDir.clone().multiplyScalar(t);
      return { x: projected.x, y: projected.y, z: projected.z };
    }
    return { x: offset.x, y: offset.y, z: offset.z };
  }

  function updateDrag(clientX: number, clientY: number): Draft3dMutation | null {
    if (!drag) return null;
    if (!setNdc(clientX, clientY)) return null;
    const delta = ndcToWorldOffset(ndc);
    const draft = drag.descriptor.onDrag(delta);
    drag.lastDelta = delta;
    drag.lastDraft = draft;
    return draft;
  }

  function endDrag(commit: boolean): void {
    if (!drag) return;
    if (drag.glow) {
      layer.remove(drag.glow);
      drag.glow.geometry.dispose();
      (drag.glow.material as THREE.Material).dispose();
    }
    if (commit) {
      const cmd = drag.descriptor.onCommit(drag.lastDelta);
      opts.dispatchCommand(cmd);
    }
    drag = null;
  }

  function getDragState() {
    if (!drag) return null;
    return {
      handleId: drag.handleId,
      draft: drag.lastDraft,
      descriptor: drag.descriptor,
    };
  }

  function dispose() {
    if (drag) endDrag(false);
    clearHandles();
    opts.scene.remove(layer);
  }

  return {
    refresh,
    tryPickHandle,
    beginDrag,
    updateDrag,
    endDrag,
    getDragState,
    dispose,
  };
}

