/**
 * EDT-03 — small radial menu shown when the user clicks a wall face
 * in the 3D viewport. Offers "Insert Door / Window / Opening", placing
 * the resulting hosted element at the click point along the wall's
 * length.
 */

import { useEffect, useRef } from 'react';

export type WallFaceRadialKind = 'door' | 'window' | 'opening';

export interface WallFaceRadialMenuProps {
  /** Screen-space position (px). */
  position: { x: number; y: number };
  /** Called when the user picks a kind. */
  onPick: (kind: WallFaceRadialKind) => void;
  /** Called when the menu should be dismissed (esc / outside click). */
  onClose: () => void;
}

const ITEMS: { id: WallFaceRadialKind; label: string; angleDeg: number }[] = [
  { id: 'door', label: 'Door', angleDeg: -90 },
  { id: 'window', label: 'Window', angleDeg: 30 },
  { id: 'opening', label: 'Opening', angleDeg: 150 },
];

const RADIUS_PX = 56;

export function WallFaceRadialMenu({ position, onPick, onClose }: WallFaceRadialMenuProps) {
  const ref = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const onKey = (ev: KeyboardEvent) => {
      if (ev.key === 'Escape') {
        ev.preventDefault();
        onClose();
      }
    };
    const onClick = (ev: MouseEvent) => {
      const node = ref.current;
      if (!node) return;
      if (!node.contains(ev.target as Node)) onClose();
    };
    document.addEventListener('keydown', onKey);
    // Wrap in microtask so the click that opened us doesn't immediately close.
    const t = setTimeout(() => {
      document.addEventListener('mousedown', onClick);
    }, 0);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.removeEventListener('mousedown', onClick);
      clearTimeout(t);
    };
  }, [onClose]);

  return (
    <div
      ref={ref}
      data-testid="wall-face-radial-menu"
      style={{
        position: 'absolute',
        left: position.x - RADIUS_PX - 16,
        top: position.y - RADIUS_PX - 16,
        width: 2 * (RADIUS_PX + 16),
        height: 2 * (RADIUS_PX + 16),
        pointerEvents: 'none',
        zIndex: 30,
      }}
    >
      <div
        style={{
          position: 'absolute',
          left: '50%',
          top: '50%',
          width: 16,
          height: 16,
          marginLeft: -8,
          marginTop: -8,
          borderRadius: '50%',
          background: 'rgba(20,28,42,0.92)',
          border: '1px solid rgba(125,211,252,0.6)',
        }}
      />
      {ITEMS.map((it) => {
        const rad = (it.angleDeg * Math.PI) / 180;
        const x = Math.cos(rad) * RADIUS_PX;
        const y = Math.sin(rad) * RADIUS_PX;
        return (
          <button
            key={it.id}
            type="button"
            data-testid={`wall-face-radial-${it.id}`}
            onClick={(ev) => {
              ev.stopPropagation();
              onPick(it.id);
            }}
            style={{
              position: 'absolute',
              left: '50%',
              top: '50%',
              transform: `translate(${x - 28}px, ${y - 12}px)`,
              pointerEvents: 'auto',
              cursor: 'pointer',
              minWidth: 56,
              padding: '4px 8px',
              fontSize: 11,
              fontFamily:
                'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Monaco, Consolas, monospace',
              background: 'rgba(20,28,42,0.92)',
              color: '#e2e8f0',
              border: '1px solid rgba(125,211,252,0.4)',
              borderRadius: 4,
            }}
          >
            {it.label}
          </button>
        );
      })}
    </div>
  );
}

